import * as SQLite from 'expo-sqlite';

const db = SQLite.openDatabase('todo.db');

async function createTable() {
  return new Promise((resolve) => {
    db.transaction(txn => txn.executeSql(
      `CREATE TABLE IF NOT EXISTS todos (id INTEGER PRIMARY KEY, title TEXT)`,
      [],
      () => resolve(),
      (_, error) => console.error(error)
    ));
  });
}

createTable();

const TodoApp = () => {
  const [todos, setTodos] = useState([]);
  const [newTodoTitle, setNewTodoTitle] = useState('');

  async function addTodo() {
    await db.transaction(txn => txn.executeSql(
      `INSERT INTO todos (title) VALUES (?)`,
      [newTodoTitle],
      (_, result) => console.log(result.insertId),
      (_, error) => console.error(error)
    ));
    setNewTodoTitle('');
    loadTodos();
  }

  async function deleteTodo(id) {
    await db.transaction(txn => txn.executeSql(
      `DELETE FROM todos WHERE id = ?`,
      [id],
      () => console.log('Deleted'),
      (_, error) => console.error(error)
    ));
    loadTodos();
  }

  async function loadTodos() {
    const result = await db.transaction(txn => txn.executeSql(
      'SELECT * FROM todos',
      [],
      (_, result) => setTodos(result.rows._array),
      (_, error) => console.error(error)
    ));
  }

  React.useEffect(() => {
    loadTodos();
  }, []);

  return (
    <View style={styles.container}>
      <TextInput
        style={styles.input}
        placeholder="New Todo"
        value={newTodoTitle}
        onChangeText={setNewTodoTitle}
      />
