import React from 'react';
import { View, StyleSheet } from 'react-native';
import Animated, { Easing } from 'react-native-reanimated';
import { PanGestureHandler, State } from 'react-native-gesture-handler';

const DraggableBox = () => {
  const [position, setPosition] = React.useState({ x: 0, y: 0 });
  const [originalPosition, setOriginalPosition] = React.useState({ x: 0, y: 0 });

  const panGestureHandler = React.useRef(null);

  const handlePanEvent = ({ nativeEvent }) => {
    if (nativeEvent.state === State.ACTIVE) {
      setPosition({
        x: nativeEvent.translationX,
        y: nativeEvent.translationY,
      });
    }
    if (nativeEvent.state === State.END) {
      panGestureHandler.current?.reset();
      const { translationX, translationY } = nativeEvent;
      const newX = Math.min(Math.max(translationX, -100), 100);
      const newY = Math.min(Math.max(translationY, -100), 100);

      Animated.timing(position, {
        toValue: { x: newX, y: newY },
        duration: 300,
        easing: Easing.inOut(Easing.quad),
        useNativeDriver: true,
      }).start(() => setOriginalPosition({ x: newX, y: newY }));
    }
  };

  return (
    <PanGestureHandler onGestureEvent={handlePanEvent} ref={panGestureHandler}>
      <Animated.View
        style={[
          styles.box,
          {
            transform: [
              { translateX: position.x },
              { translateY: position.y },
            ],
          },
        ]}
      />
    </PanGestureHandler>
  );
};

const styles = StyleSheet.create({
  box: {
    width: 100,
    height: 100,
    backgroundColor: 'blue',
    justifyContent: 'center',
    alignItems: 'center',
  },
});

export default DraggableBox;

import React from 'react';
import { View } from 'react-native';
import Animated, { useSharedValue, useAnimatedStyle, withSpring } from 'react-native-reanimated';
import { PanGestureHandler } from 'react-native-gesture-handler';

const SwipeableCardStack = () => {
  const cardIndex = useSharedValue(0);
  const translateY = useSharedValue(0);

  const panGestureHandler = {
    onActive: (event) => {
      translateY.value = event.translationY;
    },
    onEnd: (event) => {
      if (translateY.value > 150) {
        cardIndex.value = Math.min(cardIndex.value - 1, 0);
        translateY.value = useSharedValue(0);
      } else if (translateY.value < -150) {
        cardIndex.value = Math.max(cardIndex.value + 1, 0);
        translateY.value = useSharedValue(0);
      }
    },
  };

  const animatedStyle = useAnimatedStyle(() => ({
    transform: [
      { translateY: translateY.value },
    ],
  }));

  return (
    <View>
      <PanGestureHandler onGestureEvent={panGestureHandler}>
        <Animated.View style={[animatedStyle, { height: 200 }]}>
          {Array.from({ length: 5 }, (_, index) => {
            const isCurrentCard = cardIndex.value === index;
            return (
              <View key={index} style={{ backgroundColor: isCurrentCard ? 'red' : 'blue', height: 180 }}>
                {isCurrentCard && <Text>Swipe me!</Text>}
              </View>
            );
          })}
        </Animated.View>
